VALUES
  ('real-estate-appraiser-moex-00072', 'real-estate-appraiser', 'real-estate-appraiser-moex-111-ba81c82b', 'sub-real-estate-appraiser-04', NULL, 'essay', '近年來，由於氣候變遷迅速，水稻梯田（Riceterraces）具有氣候韌性的
近似公共財功能，再度受到重視；然因其位居山坡地，從而棄耕的現象
時有所聞。試說明水稻梯田具有近似公共財的特性為何？倘因棄耕可能
對國民福祉產生何等損失？如為避免此種現象滋生，政府可採何種對策
以為因應？請繪圖解析並闡述己見。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:30+00:00", "source_pdf_sha1": "19674fc33f32", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "905", "s": "0305", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "不動產經濟學", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00073', 'real-estate-appraiser', 'real-estate-appraiser-moex-111-ba81c82b', 'sub-real-estate-appraiser-04', NULL, 'essay', '自今（111）年 7月起，有多個縣市將對持有一定戶數以上者課徵最高稅
率的房屋稅，此舉恐造成稅負轉嫁、租屋者負擔驟增之批評，請以從價
稅繪圖分析地方政府採此措施可能對社會福利造成之影響，並闡述政府
可採因應之道。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:30+00:00", "source_pdf_sha1": "19674fc33f32", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "905", "s": "0305", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "不動產經濟學", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00074', 'real-estate-appraiser', 'real-estate-appraiser-moex-111-707b521e', 'sub-real-estate-appraiser-05', NULL, 'essay', '現有一筆非都市土地，如分依國土計畫法與區域計畫法，申請使用許可
與開發許可，兩者各應如何申請？在民眾參與及資訊告知程序有何不
同？兩者之審查條件又有何差異？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:30+00:00", "source_pdf_sha1": "52eae7cff297", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "905", "s": "0302", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "土地利用法規", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00075', 'real-estate-appraiser', 'real-estate-appraiser-moex-111-707b521e', 'sub-real-estate-appraiser-05', NULL, 'essay', '關於產業專用區（或相關產業用地）劃設，依都市計畫法及都市計畫法
臺灣省施行細則相關規定，其相關細部計畫擬定，須涵蓋那些內容？此
產業專用區劃設，如為提升能源使用效率及設置再生能源發電設備，在
符合那些條件下，除擴大投資或產業升級轉型之興辦事業計畫容積獎勵
外，可進一步獲得那些容積獎勵？其容積獎勵又有何限制？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:30+00:00", "source_pdf_sha1": "52eae7cff297", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "905", "s": "0302", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "土地利用法規", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00076', 'real-estate-appraiser', 'real-estate-appraiser-moex-111-707b521e', 'sub-real-estate-appraiser-05', NULL, 'essay', '請依市地重劃相關法令規定，說明辦理市地重劃過程，計算參與重劃人
數與面積之基準為何？辦理重劃前後地價查估應依那些規定或原則？
而關於重劃區之抵費地，其定價原則為何？抵費地於重劃土地分配結果
公告確定後，主管機關又應如何處理？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:30+00:00", "source_pdf_sha1": "52eae7cff297", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "905", "s": "0302", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "土地利用法規", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00077', 'real-estate-appraiser', 'real-estate-appraiser-moex-111-707b521e', 'sub-real-estate-appraiser-05', NULL, 'essay', '縣市政府為開發公共設施，擬徵收數筆土地，然該土地上具有建築改良
物，試問縣市政府應如何處理？土地與建築改良物之補償基準各為何？
此基準各如何評（估）定？何種情況縣市政府須擬定安置計畫？安置範
圍為何？那些情況又須發給遷移費？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:30+00:00", "source_pdf_sha1": "52eae7cff297", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "905", "s": "0302", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "土地利用法規", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00078', 'real-estate-appraiser', 'real-estate-appraiser-moex-111-9cd45b90', 'sub-real-estate-appraiser-06', NULL, 'essay', '民法第 823條第1 項規定：「各共有人，除法令另有規定外，得隨時請求
分割共有物。但因物之使用目的不能分割或契約訂有不分割之期限者，
不在此限。」試問：前開規定所稱「法令另有規定」及「因物之使用目
的不能分割」之意涵為何？請舉例闡明之。又，分別共有土地之共有人
依民法第824條第 2 項規定請求法院裁判分割時，其分割方法為何？請
申述之。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:30+00:00", "source_pdf_sha1": "3452034bbd0b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "905", "s": "0301", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法物權與不動產法規", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00079', 'real-estate-appraiser', 'real-estate-appraiser-moex-111-9cd45b90', 'sub-real-estate-appraiser-06', NULL, 'essay', '甲、乙 2 人共有（應有部分各 2 分之 1）面積 400 平方公尺之 A 地；2
人並訂定分管契約，約定各自使用 200平方公尺之特定位置。嗣甲將其
分管範圍內之 100 平方公尺土地建築 1 棟未辦所有權第一次登記之房
屋，與其配偶丙共同居住使用，其餘 100 平方公尺土地則出借予丁建屋
居住使用。之後，甲死亡，其唯一繼承人丙逾期未辦理繼承登記。於是，
該原屬甲所有 A地之應有部分 2分之 1，經主管地政機關依土地法第 73
條之 1 規定程序予以列冊管理逾 15 年，惟丙仍未申辦繼承登記；地政
機關遂移請財政部國有財產署公開標售，並由戊得標。試問：於前述設
例之情況，依土地法之規定，何人對該標售之 A地應有部分 2分之 1 有
優先購買權？如各優先購買權人均有意優先承購時，財政部國有財產署
應如何處理之？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:30+00:00", "source_pdf_sha1": "3452034bbd0b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "905", "s": "0301", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法物權與不動產法規", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00080', 'real-estate-appraiser', 'real-estate-appraiser-moex-111-9cd45b90', 'sub-real-estate-appraiser-06', NULL, 'essay', '甲於民國 90 年 1月購買取得 A地號土地；93 年 9月，A地號土地因辦
理市地重劃，甲經重劃公告確定分配取得B地號土地。嗣甲於100年9月
死亡，B地號土地於 101 年 7月經辦竣繼承登記為甲之繼承人乙之名義。
110 年 8 月，乙出售 B 地號土地予丙，並依法申報移轉現值。試問：關
於乙應納之土地增值稅，是否有土地稅法第 39條之 1 第 1 項規定：「經
重劃之土地，於重劃後第一次移轉時，其土地增值稅減徵百分之四十。」
之適用？又，依土地稅法第22條第1項規定，依法限制建築或依法不能
建築，仍作農業使用之都市土地，徵收田賦；其所稱「依法限制建築」及
「依法不能建築」之意涵為何？以上兩項問題，請申述之。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:30+00:00", "source_pdf_sha1": "3452034bbd0b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "905", "s": "0301", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法物權與不動產法規", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00081', 'real-estate-appraiser', 'real-estate-appraiser-moex-111-9cd45b90', 'sub-real-estate-appraiser-06', NULL, 'essay', '平均地權條例第64 條第 1項規定：「地上權、農育權、永佃權及不動產
役權因市地重劃致不能達其設定目的者，各該權利視為消滅。地上權人、
農育權人、永佃權人或不動產役權人得向土地所有權人請求相當之補
償。」試問：前揭規定所稱「因市地重劃致不能達其設定目的者」，其情
形為何？又，如各該權利，因市地重劃致不能達其設定目的，而視為消
滅，致應予補償，並委由不動產估價師估計補償金額時，依不動產估價
技術規則規定，其估價應考慮之因素為何？請申述之。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:30+00:00", "source_pdf_sha1": "3452034bbd0b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "905", "s": "0301", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法物權與不動產法規", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL)
